<x-layouts.panel title="Blog Yazısı"><form method="POST" action="{{ $post->exists ? route('admin.blog-posts.update',$post) : route('admin.blog-posts.store') }}" class="panel grid gap-4 max-w-3xl">@csrf @if($post->exists) @method('PUT') @endif<h1 class="text-2xl font-bold">Blog Yazısı</h1><label><span class="label">Başlık</span><input class="field" name="title" value="{{ old('title',$post->title) }}"></label><label><span class="label">Slug</span><input class="field" name="slug" value="{{ old('slug',$post->slug) }}"></label><label><span class="label">Özet</span><textarea class="field" name="excerpt">{{ old('excerpt',$post->excerpt) }}</textarea></label><label><span class="label">İçerik</span><textarea class="field min-h-64" name="body">{{ old('body',$post->body) }}</textarea></label><label><span class="label">Meta başlık</span><input class="field" name="meta_title" value="{{ old('meta_title',$post->meta_title) }}"></label><label><span class="label">Meta açıklama</span><input class="field" name="meta_description" value="{{ old('meta_description',$post->meta_description) }}"></label><label><span class="label">Etiketler</span><input class="field" name="tags" value="{{ old('tags', implode(',', $post->tags ?? [])) }}"></label><label><span class="label">Durum</span><select class="field" name="status"><option value="draft" @selected($post->status==='draft')>Taslak</option><option value="published" @selected($post->status==='published')>Yayında</option></select></label><button class="btn-primary w-fit">Kaydet</button></form></x-layouts.panel>
